using System.IO.Compression;
using System.Text;

class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 now sets the UTF-8 flag on ZipArchiveEntry names by default.
        // The legacy Java consumer reads filenames as Shift-JIS, so we must
        // explicitly use Shift-JIS encoding to avoid the UTF-8 flag being set.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("Shift-JIS");

        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("Ńā¼ŃāØŃā╝Ńāł/µ£łµ¼Ī.csv");  // Japanese path
        archive.CreateEntry("donn├®es/r├®sum├®.txt"); // French accented
    }
}

